module top_module(output reg [3:0]Z, input [1:0]op, input [3:0] obf_A, B, C);always @(*)
    begin
        case(op)
            2'b00: Z = obf_A + B + C;
            2'b01: Z = obf_A - B - C;
            2'b10: Z = obf_A & B & C;
            2'b11: Z = obf_A | B | C;
        endcase
    end
endmodule
